"""calus: session-token  (30 patterns)"""

PATTERNS = [
    ('(?i)(?:jwt[_-]?secret|jwt[_-]?key|session[_-]?token)\\s*[:=]\\s*[\'"][^\'"]{16,}[\'"]', 'high', 'mcp-session-token-hardcoded-jwt: Detects hardcoded JWT secrets or session tokens in code, enabling token reuse or replay (A2A token-lifetime'),
    ('(?i)(?:jwt|token).{0,30}(?:.encode|.decode|sign)\\s*\\(\\s*[\'"][^\'"]{8,}[\'"]\\s*,\\s*[\'"](?:secret|key|hardcoded)[\'"]', 'high', 'mcp-session-token-hardcoded-jwt: Detects hardcoded JWT secrets or session tokens in code, enabling token reuse or replay (A2A token-lifetime'),
    ('(?i)\\b(?:print|log|logging|logger|warn|critical)\\s*\\([^)]*\\bsession[_-]?(?:id|token)\\b[^)]*\\b(?:id|token|secret|key)\\b', 'critical', 'mcp-session-token-exposure-logging: Session token or credential exposure via MCP logging: detection of log statements that output sensitive '),
    ('(?i)read_file\\([\'"](?:\\/|\\\\)?(?:etc|var|home|users|app).{0,60}(?:token|credential|secret|key|session|passw)', 'high', 'mcp-session-token-credential-exposure-scan: Detects MCP server code that exposes session tokens or credentials via file-reading tools or met'),
    ('(?i)MCP[_-]?(?:TOKEN|SESSION[_-]?ID|AUTH[_-]?KEY|SECRET|API[_-]?KEY)\\s*[:=]\\s*[\'"]?[A-Za-z0-9_\\-]{16,}', 'low', 'mcp-session-token-exposure-in-config: Detects exposure of session tokens, API keys, or credentials within MCP configuration files or environ'),
    ('(?i)session[_-]?(?:id|token)\\s*[:=]\\s*[\'"](?:sk-|eyJ|ghp_|gho_|xox[baprs]-)[A-Za-z0-9_\\-]{10,}', 'low', 'mcp-session-token-exposure-in-config: Detects exposure of session tokens, API keys, or credentials within MCP configuration files or environ'),
    ('(?i)session.{0,20}(?:token|id).{0,40}(?:return|send|write|emit)', 'medium', 'mcp-session-token-credential-exposure: Detects MCP server code that exposes session tokens or credentials in tool responses (paper §IV-D).'),
    ('(?i)session[\'"]?:\\s*[\'"][A-Za-z0-9+/=]{20,}[\'"]', 'low', 'mcp-session-token-exposure-server: Detects MCP servers that expose session identifiers, credentials, or sensitive metadata without adequate '),
    ('(?i)(?:api[_-]?key|token|secret|credential)\\s*[:=]\\s*[\'"][A-Za-z0-9+/=]{20,}[\'"]', 'low', 'mcp-session-token-exposure-server: Detects MCP servers that expose session identifiers, credentials, or sensitive metadata without adequate '),
    ('(?i)file:///.{0,40}(?:config|credentials|token)\\.json', 'low', 'mcp-session-token-exposure-server: Detects MCP servers that expose session identifiers, credentials, or sensitive metadata without adequate '),
    ('(?i)(?:env|environment)\\s*\\[\\s*[\'"]?(?:SESSION_TOKEN|API_KEY|SECRET|ACCESS_TOKEN)[\'"]?\\s*\\]', 'high', 'mcp-session-token-credential-exposure: Detects exposure of session tokens or credentials in MCP server configurations or logs, a data leakag'),
    ('(?i)(?:os\\.environ|process\\.env|env\\.get)\\(\\s*[\'"](?:SESSION_TOKEN|API_KEY|SECRET|ACCESS_TOKEN)[\'"]', 'high', 'mcp-session-token-credential-exposure: Detects exposure of session tokens or credentials in MCP server configurations or logs, a data leakag'),
    ('(?i)\\bsession[_-]?token\\b.{0,40}[=:]{1,2}\\s*[\'"][A-Za-z0-9\\-_]{20,}[\'"]', 'high', 'mcp-session-token-hardcoded-in-server: Detects hardcoded session tokens or credentials in MCP server scripts, enabling session hijacking as '),
    ('(?i)(?:from|import).{0,40}session[_-]?token\\s*=', 'high', 'mcp-session-token-hardcoded-in-server: Detects hardcoded session tokens or credentials in MCP server scripts, enabling session hijacking as '),
    ('(?i)\\b(?:session|auth|token|api.?key|secret|credential)\\s*[:=]\\s*[\'"](?:[A-Za-z0-9+/=]{20,}|sk-[a-zA-Z0-9]{20,}|eyJ[a-zA-Z0-9_-]+\\.[a-zA-Z0-9_-]+\\.[a-zA-Z0-9_-]+)[\'"]', 'low', 'mcp-session-token-credential-exposure-pattern: Detects exposure of session tokens or credentials in MCP related code, addressing data leakag'),
    ('(?i)\\b(?:bearer|basic)\\s+[\'"][A-Za-z0-9+/=]{20,}[\'"]', 'low', 'mcp-session-token-credential-exposure-pattern: Detects exposure of session tokens or credentials in MCP related code, addressing data leakag'),
    ('(?i)\\b(?:password|passwd|pwd)\\s*[:=]\\s*[\'"][^\'"\\s]{8,}[\'"]', 'low', 'mcp-session-token-credential-exposure-pattern: Detects exposure of session tokens or credentials in MCP related code, addressing data leakag'),
    ('(?i)credentials?\\s*[:=]\\s*[\'"][^\'"]{8,}[\'"]', 'low', 'mcp-session-token-credential-exposure-scanner: Detects exposure of session tokens or credentials in MCP tool configurations or logs, as desc'),
    ('(?i)(?:Authorization|X-API-Key)\\s*:\\s*[\'"][a-zA-Z0-9_-]{16,}[\'"]', 'critical', 'mcp-session-token-hardcoded-exposure: Detects hardcoded session tokens or credentials in MCP server code that could lead to leakage (Piazza '),
    ('(?i)(?:api[_-]?key|token|secret|password)\\s*[=:]\\s*[\'"](?:sk-[a-zA-Z0-9]{20,}|[a-fA-F0-9]{32}|[A-Za-z0-9+/]{40,}=*)\\b', 'high', 'mcp-session-token-credential-hardcoded: Detects hardcoded session tokens, API keys, or credentials in MCP server configuration files, enabli'),
    ('(?i)"(?:apiKey|token|secret|credential)"\\s*:\\s*[\'"](?:sk-[a-zA-Z0-9]{20,}|[a-fA-F0-9]{32}|[A-Za-z0-9+/]{40,}=*)\\b', 'high', 'mcp-session-token-credential-hardcoded: Detects hardcoded session tokens, API keys, or credentials in MCP server configuration files, enabli'),
    ('(?i)\\b(?:bearer|basic|oauth)\\b.{0,40}\\b(?:[A-Za-z0-9+/]{20,})\\b', 'low', 'mcp-session-token-credential-exposure: Detects potential exposure of session tokens, API keys, or credentials in MCP logs or tool outputs.'),
    ('(?i)(?:session[_-]?token|api[_-]?key|access[_-]?key|secret[_-]?key|password|token)\\s*.?=\\s*[\'"][A-Za-z0-9+/=]{20,}[\'"]', 'high', 'mcp-session-token-hardcoded-credential: Detects hardcoded session tokens, API keys, or passwords in MCP server source files or configuration'),
    ('(?i)\\b(?:ghp_[A-Za-z0-9]{36}|sk-[A-Za-z0-9]{20,}|AKIA[0-9A-Z]{16}|eyJ[A-Za-z0-9_-]{10,}\\.[A-Za-z0-9_-]{10,}\\.[A-Za-z0-9_-]{10,})\\b', 'high', 'mcp-session-token-hardcoded-credential: Detects hardcoded session tokens, API keys, or passwords in MCP server source files or configuration'),
    ('(?i)(?:mcp_token|mcp_session|mcp_api_key)\\s*=\\s*[\'"][A-Za-z0-9_\\-]{16,}[\'"]', 'critical', 'mcp-session-token-hardcoded-exposure: Detects hardcoded MCP session tokens or credentials in source code, enabling session hijacking as per '),
    ('(?i)(?:bearer|token)\\s*:\\s*[\'"][A-Za-z0-9_\\-]{16,}[\'"].{0,60}(?:mcp|session)', 'critical', 'mcp-session-token-hardcoded-exposure: Detects hardcoded MCP session tokens or credentials in source code, enabling session hijacking as per '),
    ('(?i)os\\.environ\\.get\\([\'"](?:MCP_TOKEN|MCP_SESSION|MCP_API_KEY)[\'"]', 'critical', 'mcp-session-token-hardcoded-exposure: Detects hardcoded MCP session tokens or credentials in source code, enabling session hijacking as per '),
    ('(?i)\\b(?:session|token|credential|api_key|secret).{0,40}(?:log|print|expose|send|output).{0,20}(?:user_input|tool_args|request\\.|params?|payload|stdin|argv|untrusted|external)', 'medium', 'mcp-session-token-exposure-code: Detects code that exposes session identifiers or tokens in MCP messages or logs (Piazza).'),
    ('(?i)session.{0,8}(?:token|id|key).{0,8}[=:].{0,8}[A-Za-z0-9+/=]{20,}', 'low', 'mcp-session-token-exposure-in-log: Detects exposure of session tokens or credentials in MCP log files, which can lead to session hijacking o'),
    ('(?i)(?:session_token|api_key|secret|password|token|credential).{0,40}(?:param|parameter|arg|argument|field|input).{0,20}(?:user_input|tool_args|request\\.|params?|payload|stdin|argv|untrusted|external)', 'medium', 'mcp-session-token-credential-exposure-tool-param: Detects MCP tool definitions that expose session tokens or credentials in parameters, enab'),
]